sys_ws_operation.operation_script:
(function process(request, response) {
  var utils = new AlationUtils();

  var q        = request.queryParams || {};
  var query    = (q.query || '').toString().trim();
  var start    = Math.max(0, parseInt(q.start || q.start_at || '0', 10) || 0);
  var max_results = Math.min(50, Math.max(1, parseInt(q.limit || q.max_results || '25', 10) || 25));

  var gr = new GlideRecord('sys_user_group');
  if (query) {
    var or = gr.addQuery('name', 'CONTAINS', query);
    or.addOrCondition('description', 'CONTAINS', query);
  }
  gr.addQuery('active', true);
  gr.orderBy('name');
  gr.query();

  var results = [];
  var skipped = 0;
  var returned = 0;
  var more = false;

  while (gr.next()) {
    if (skipped < start) { skipped++; continue; }
    if (returned >= max_results) { more = true; break; }

    results.push({
      account_id: String(gr.sys_id),
      name: String(gr.name || ''),
      display_name: String(gr.getDisplayValue('name') || ''),
      description: String(gr.description || '')
    });
    returned++;
  }

  var nextStart = more ? (start + returned) : null;

  return utils.ok(response, 200, {
    results: results,
    startAt: start,
    maxResults: max_results,
    nextStartAt: nextStart
  });
})(request, response);
